vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    // Build the graph
    vector<vector<long long>> graph(c + 1);
    for (auto& conn : connections) {
        long long u = conn[0];
        long long v = conn[1];
        graph[u].push_back(v);
        graph[v].push_back(u);
    }

    // DSU (Disjoint Set Union) to find connected components
    vector<long long> parent(c + 1);
    vector<long long> rank(c + 1);
    vector<bool> is_online(c + 1, true);

    // Initialize DSU
    for (long long i = 1; i <= c; ++i) {
        parent[i] = i;
        rank[i] = 1;
    }

    // Find function with path compression
    auto find = [&](long long x) -> long long {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    // Union function
    auto union_set = [&](long long x, long long y) -> bool {
        long long root_x = find(x);
        long long root_y = find(y);
        if (root_x == root_y) {
            return false;
        }
        if (rank[root_x] < rank[root_y]) {
            parent[root_x] = root_y;
        } else {
            parent[root_y] = root_x;
            if (rank[root_x] == rank[root_y]) {
                ++rank[root_x];
            }
        }
        return true;
    };

    // Build the DSU structure
    for (long long i = 1; i <= c; ++i) {
        for (auto& neighbor : graph[i]) {
            if (i < neighbor) {
                union_set(i, neighbor);
            }
        }
    }

    vector<long long> result;

    // Process queries
    for (auto& query : queries) {
        long long type = query[0];
        long long x = query[1];
        if (type == 1) {
            if (is_online[x]) {
                result.push_back(x);
            } else {
                long long root = find(x);
                long long min_id = -1;
                for (long long i = 1; i <= c; ++i) {
                    if (is_online[i] && find(i) == root) {
                        if (min_id == -1 || i < min_id) {
                            min_id = i;
                        }
                    }
                }
                result.push_back(min_id);
            }
        } else {
            is_online[x] = false;
        }
    }

    return result;
}

